}

function profileRect(widthMm, depthMm) {
  const w = widthMm / 2;
  const d = depthMm / 2;
  return [
    { uMm: -w, vMm: -d },
    { uMm: w, vMm: -d },
    { uMm: w, vMm: d },
    { uMm: -w, vMm: d },
  ];
}

function sweep(id, name, pathMm, materialKey, widthMm = 45, depthMm = 45) {
  return {
    type: 'createSweep',
    id,
    name,
    levelId: 'hf-lvl-ground',
    pathMm,
    profileMm: profileRect(widthMm, depthMm),
