  await page.evaluate((snap) => {
    type StoreShape = {
      getState: () => {
        hydrateFromSnapshot: (s: SnapshotShape) => void;
      };
    };
    const win = window as unknown as { __bimStore?: StoreShape };
    if (!win.__bimStore) throw new Error('window.__bimStore not exposed');
